INSERT INTO `article` (`article_id`, `title`, `summary`, `content`, `thumbnail`, `status`, `view_count`, `created_at`, `updated_at`, `user_id`, `category_id`) VALUES
(2, 'Ông Nghiêm Xuân Thành làm Phó chủ nhiệm Ủy ban Kiểm tra Trung ương', 'Ông Nghiêm Xuân Thành, 57 tuổi, Ủy viên Ủy ban Kiểm tra Trung ương, được bầu giữ chức Phó chủ nhiệm Ủy ban.', 'Ủy ban Kiểm tra Trung ương vừa cập nhật thông tin các Phó chủ nhiệm Ủy ban, trong đó có ông Nghiêm Xuân Thành. Ba ngày trước, tại Hội nghị Trung ương 2 khóa 14, ông Nghiêm Xuân Thành được bầu làm Ủy viên Ủy ban Kiểm tra Trung ương khóa 14, nhiệm kỳ 2026-2031.\r\n\r\nÔng Nghiêm Xuân Thành quê xã Yên Lạc, tỉnh Phú Thọ, là tiến sĩ Kinh tế, thạc sĩ Tài chính - Tiền tệ - Tín dụng, cử nhân Kế toán, Ủy viên Trung ương Đảng khóa 13, 14.\r\n\r\nÔng Nghiêm Xuân Thành. Ảnh: Bùi Toàn\r\nÔng Nghiêm Xuân Thành. Ảnh: Bùi Toàn\r\n\r\nHơn 30 năm công tác trong ngành ngân hàng, ông Thành khởi đầu tại Ngân hàng Thương mại cổ phần Công thương Việt Nam (VietinBank) chi nhánh Vĩnh Phúc (nay là Phú Thọ), sau đó giữ nhiều vị trí như Phó chánh Văn phòng, Thư ký Tổng giám đốc; Trưởng ban Thư ký Hội đồng quản trị; Trưởng phòng Quản lý rủi ro và nợ có vấn đề.\r\n\r\nÔng từng làm Giám đốc chi nhánh VietinBank Thanh Xuân, Đống Đa; rồi giữ chức Phó tổng giám đốc VietinBank từ đầu năm 2012. Sáu tháng sau, ông được điều động làm Chánh văn phòng Ngân hàng Nhà nước, trước khi giữ các vị trí Tổng giám đốc, Chủ tịch Hội đồng quản trị Ngân hàng Thương mại cổ phần Ngoại thương Việt Nam (Vietcombank).\r\n\r\nGiữa năm 2021, Bộ Chính trị luân chuyển, chỉ định ông làm Bí thư Tỉnh ủy Hậu Giang (nay là TP Cần Thơ), sau đó giữ chức Bí thư Tỉnh ủy Khánh Hòa. Từ tháng 7/2025, khi Khánh Hòa sáp nhập với Ninh Thuận, ông được chỉ định làm Bí thư tỉnh Khánh Hòa mới và đảm nhiệm cương vị này gần một năm.\r\n\r\nTại Đại hội Đảng lần thứ 14, ông tái cử Ủy viên Trung ương Đảng.\r\n\r\nỦy ban Kiểm tra Trung ương là cơ quan kiểm tra, giám sát chuyên trách của Ban Chấp hành Trung ương, có chức năng tham mưu, giúp Ban Chấp hành Trung ương, Bộ Chính trị, Ban Bí thư tổ chức thực hiện nhiệm vụ kiểm tra, giám sát và kỷ luật của Đảng.\r\n\r\nChủ nhiệm Ủy ban Kiểm tra Trung ương là ông Trần Sỹ Thanh, cùng 9 phó chủ nhiệm gồm các ông: Trần Tiến Hưng (Thường trực), Nguyễn Hồng Lĩnh, Hà Quốc Trị, Đoàn Anh Dũng, Đinh Hữu Thành, Nguyễn Minh Quang, Lê Văn Thành, Nghiêm Xuân Thành và bà Trần Thị Hiền. Ủy ban hiện có 13 Ủy viên.', 'assets/uploads/thumb_69c8201336d258.12169086_small.webp', 'published', 13, '2026-03-29 01:38:11', '2026-03-30 04:33:04', 3, 1),
(3, 'Bầu Chủ tịch nước, Thủ tướng, Chủ tịch Quốc hội khóa mới vào đầu tháng 4', 'Quốc hội sẽ kiện toàn các chức danh Chủ tịch nước, Thủ tướng, Chủ tịch Quốc hội, Phó chủ tịch Quốc hội, Phó thủ tướng nhiệm kỳ 2026-2031 tại kỳ họp thứ nhất, diễn ra đầu tháng 4.\r\n\r\n', 'Sáng 26/3, Chủ tịch Quốc hội Trần Thanh Mẫn chủ trì cuộc họp về công tác chuẩn bị kỳ họp thứ nhất, Quốc hội khóa 16. Ông cho biết kỳ họp có ý nghĩa đặc biệt quan trọng khi xem xét kiện toàn nhân sự các chức danh của Nhà nước, gồm Chủ tịch nước, Thủ tướng, Chủ tịch Quốc hội, các Phó chủ tịch Quốc hội, Phó thủ tướng, thành viên của Chính phủ, Ủy viên Ủy ban Thường vụ Quốc hội, Hội đồng Dân tộc và các Ủy ban của Quốc hội.\r\n\r\nTheo kế hoạch, kỳ họp thứ nhất khai mạc sáng 6/4, dự kiến bế mạc ngày 24/4, làm việc trong 11 ngày và chia thành 2 đợt. Ngoài xem xét, quyết định công tác tổ chức bộ máy, nhân sự; Quốc hội đồng thời thông qua 9 dự án luật, nghị quyết quy phạm pháp luật.\r\n\r\nNgoài ra, Quốc hội sẽ thảo luận 5 nhóm nội dung về kinh tế xã hội, tài chính, ngân sách, giám sát và các vấn đề quan trọng khác; cùng 9 nhóm nội dung gửi đại biểu nghiên cứu trước kỳ họp.\r\n\r\nChủ tịch Quốc hội Trần Thanh Mẫn yêu cầu các cơ quan tiếp tục rà soát toàn diện công tác chuẩn bị, kịp thời báo cáo, xin ý kiến lãnh đạo Quốc hội và Ủy ban Thường vụ Quốc hội đối với những nội dung còn vướng mắc. Các cơ quan của Quốc hội rà soát tiến độ chuẩn bị tài liệu thuộc lĩnh vực phụ trách để kịp gửi đại biểu trước khi khai mạc kỳ họp.\r\n\r\nThường trực Ủy ban Công tác đại biểu phối hợp chặt chẽ với Văn phòng Quốc hội chuẩn bị kịch bản điều hành nội dung về công tác tổ chức, nhân sự tại kỳ họp, bảo đảm đúng quy định của pháp luật.\r\n\r\nChủ tịch Quốc hội Trần Thanh Mẫn chủ trì cuộc họp về công tác chuẩn bị cho Kỳ họp thứ Nhất, Quốc hội khóa 16. Ảnh: Hoàng Phong\r\nChủ tịch Quốc hội Trần Thanh Mẫn chủ trì cuộc họp về công tác chuẩn bị cho Kỳ họp thứ Nhất, Quốc hội khóa 16. Ảnh: Hoàng Phong\r\n\r\nHiện nay, lãnh đạo chủ chốt của Đảng, Nhà nước gồm Tổng Bí thư Tô Lâm, Chủ tịch nước Lương Cường, Thủ tướng Phạm Minh Chính, Chủ tịch Quốc hội Trần Thanh Mẫn, Thường trực Ban Bí thư Trần Cẩm Tú.\r\n\r\nCác Phó thủ tướng gồm các ông Nguyễn Hòa Bình (thường trực), Trần Hồng Hà, Lê Thành Long, Hồ Đức Phớc, Bùi Thanh Sơn, Nguyễn Chí Dũng, Mai Văn Chính, Hồ Quốc Dũng và bà Phạm Thị Thanh Trà.\r\n\r\nCác Phó chủ tịch Quốc hội gồm ông Đỗ Văn Chiến (thường trực), Nguyễn Khắc Định, Nguyễn Đức Hải, Trần Quang Phương, Vũ Hồng Thanh, Lê Minh Hoan và bà Nguyễn Thị Thanh.\r\n\r\nTheo thông cáo phát chiều 25/3, tại hội nghị Trung ương 2 khóa 14, Ban chấp hành Trung ương đã đồng ý Tờ trình của Bộ Chính trị về cơ cấu tổ chức bộ máy Nhà nước và phương án giới thiệu nhân sự đảm nhiệm các chức danh lãnh đạo cơ quan Nhà nước nhiệm kỳ 2026-2031. Trung ương giao Bộ Chính trị căn cứ kết quả lấy ý kiến, biểu quyết chính thức giới thiệu nhân sự để hoàn tất thủ tục trình Quốc hội bầu hoặc phê chuẩn theo quy định.\r\n\r\n', 'assets/uploads/thumb_69c8206f7e0f56.28830184_small.webp', 'published', 4, '2026-03-29 01:39:43', '2026-03-30 01:24:37', 4, 1),
(4, 'Đồng Nai thêm 10 phường sau sáp nhập, mở rộng không gian đô thị', 'Các phường mới hình thành từ huyện lỵ cũ, tạo nền tảng để Đồng Nai hoàn thiện tiêu chí đô thị loại I và hướng tới mô hình thành phố trực thuộc Trung ương.\r\n\r\n', 'Sáng 28/3, HĐND tỉnh Đồng Nai biểu quyết thông qua chủ trương thành lập 10 phường trực thuộc tỉnh, gồm: Long Thành, Nhơn Trạch, Trảng Bom, Xuân Lộc, Dầu Giây, Tân Phú, Trị An, Đồng Phú, Tân Khai và Lộc Ninh.\r\n\r\nCác phường này được hình thành trên cơ sở các thị trấn (huyện lỵ) trước khi tổ chức lại đơn vị hành chính. Trong đó, 7 phường thuộc địa bàn Đồng Nai cũ và 3 phường thuộc Bình Phước cũ. Riêng phường Long Thành gắn với khu vực sân bay quốc tế Long Thành, được kỳ vọng trở thành cực tăng trưởng đô thị trong thời gian tới.\r\n\r\nTrước khi điều chỉnh, Đồng Nai có 23 phường, với trung tâm hành chính đặt tại phường Trấn Biên. Trong số này, các phường Biên Hòa, Trấn Biên, Tam Hiệp, Long Bình, Phước Tân, Tam Phước và Xuân Lập đạt trình độ phát triển hạ tầng đô thị loại II; 16 phường còn lại đạt đô thị loại III.\r\n\r\nCũng tại kỳ họp, HĐND tỉnh thông qua đề án công nhận Đồng Nai đạt tiêu chí đô thị loại I và tán thành chủ trương thành lập thành phố Đồng Nai trực thuộc Trung ương.\r\n\r\nTheo đề án, thành phố Đồng Nai sẽ được hình thành trên cơ sở giữ nguyên hiện trạng diện tích và dân số của tỉnh sau sáp nhập. Hiện Đồng Nai có diện tích hơn 12.700 km2, dân số trên 4,5 triệu người, với 95 đơn vị hành chính cấp xã; trung tâm hành chính đặt tại phường Trấn Biên (TP Biên Hòa cũ).\r\n\r\nGiai đoạn 2026-2031, địa phương đặt mục tiêu GRDP tăng bình quân 10% mỗi năm; đến năm 2030 đạt trên 1,2 triệu tỷ đồng, GRDP bình quân đầu người trên 250 triệu đồng; thu ngân sách tăng 10-12% mỗi năm.\r\n\r\nNghị quyết được thông qua trên cơ sở các quy định pháp lý mới nhất về tổ chức chính quyền địa phương, phân loại đô thị và tiêu chuẩn đơn vị hành chính năm 2025, đồng thời cụ thể hóa chủ trương của Trung ương về việc thành lập thành phố Đồng Nai trực thuộc Trung ương.', 'assets/uploads/thumb_69c820ff29bff1.38523303_small.webp', 'published', 4, '2026-03-29 01:42:07', '2026-03-30 01:24:42', 5, 1),
(5, 'Tổng Bí thư: Phát triển thể thao đại chúng là nhiệm vụ trung tâm', 'Tổng Bí thư Tô Lâm yêu cầu phát triển thể thao đại chúng là nhiệm vụ trung tâm, đưa rèn luyện thân thể thành nếp sống, đồng thời hoàn thiện thể chế và đẩy mạnh xã hội hóa lĩnh vực này.\r\n\r\n', 'Sáng 28/3, Bộ Văn hóa Thể thao và Du lịch tổ chức Lễ kỷ niệm 80 năm Ngày truyền thống ngành Thể dục Thể thao Việt Nam. Phát biểu tại buổi lễ, Tổng Bí thư Tô Lâm nhấn mạnh phát triển thể dục thể thao không chỉ là nhiệm vụ của riêng ngành mà là yêu cầu chiến lược đối với phát triển con người, nâng cao chất lượng nguồn nhân lực và sức khỏe cộng đồng.\r\n\r\nNhắc lại bối cảnh sau Cách mạng Tháng Tám, Tổng Bí thư cho biết dù đất nước đứng trước nhiều khó khăn, Chủ tịch Hồ Chí Minh đã sớm nhìn ra chân lý \"dân cường thì nước thịnh\", ký sắc lệnh thành lập Nha Thể dục Trung ương, đặt nền móng cho nền thể dục thể thao cách mạng Việt Nam. Lời kêu gọi toàn dân tập thể dục của Người đến nay vẫn còn nguyên giá trị, trở thành định hướng xuyên suốt trong phát triển lĩnh vực này.\r\n\r\nTheo người đứng đầu Đảng, qua 80 năm xây dựng và trưởng thành, thể dục thể thao Việt Nam đã có những đóng góp quan trọng trên nhiều phương diện. Trước hết là nâng cao sức khỏe, thể lực, tinh thần và chất lượng sống của nhân dân, với hàng chục triệu người tham gia luyện tập thường xuyên, hình thành nếp sống vận động trong cộng đồng.\r\n\r\nCùng với đó, thể thao thành tích cao từng bước khẳng định vị thế Việt Nam tại các đấu trường khu vực và quốc tế. Những tấm huy chương, kỷ lục và hình ảnh quốc kỳ Việt Nam tung bay trên đấu trường quốc tế không chỉ là thành tích chuyên môn mà còn thể hiện ý chí, bản lĩnh và khát vọng vươn lên của dân tộc.\r\n\r\nThể dục thể thao cũng góp phần củng cố khối đại đoàn kết toàn dân tộc, lan tỏa các giá trị văn hóa, tăng cường giao lưu, hữu nghị và quảng bá hình ảnh đất nước, con người Việt Nam ra thế giới. \"Thể thao là ngôn ngữ không cần phiên dịch, là cầu nối hiệu quả giữa các quốc gia, dân tộc\", ông nhấn mạnh.\r\n\r\nNhững kết quả đó là công sức của nhiều thế hệ cán bộ, huấn luyện viên, vận động viên và những người làm công tác thể dục thể thao, với sự hy sinh thầm lặng và những đóng góp bền bỉ trong suốt nhiều năm. Đảng, Nhà nước và nhân dân luôn ghi nhận, trân trọng những đóng góp này.\r\n\r\nBước vào giai đoạn phát triển mới, Tổng Bí thư nêu rõ đất nước đang đặt ra yêu cầu rất cao về tầm vóc con người, chất lượng nguồn nhân lực, năng lực cạnh tranh quốc gia và chất lượng sống của nhân dân. Trong bối cảnh đó, cần có cách nhìn toàn diện hơn về vai trò của thể dục thể thao, coi đây là một trụ cột trong chiến lược phát triển con người.\r\n\r\nTổng Bí thư Tô Lâm cùng lãnh đạo các cơ quan, bộ ngành Trung ương tại buổi lễ. Ảnh: Hoàng Phong\r\nTổng Bí thư Tô Lâm cùng lãnh đạo các cơ quan, bộ ngành Trung ương tại buổi lễ. Ảnh: Hoàng Phong\r\n\r\nTrên cơ sở đó, Tổng Bí thư yêu cầu các bộ, ngành, địa phương và toàn xã hội tập trung thực hiện đồng bộ các nhiệm vụ trọng tâm, trước hết là khẩn trương hoàn thiện thể chế phát triển thể dục thể thao theo hướng hiện đại, đồng bộ, tạo nền tảng cho phát triển lâu dài. Thể chế phải đi trước, làm rõ vai trò của Nhà nước và xã hội, xác định cụ thể cơ chế quản trị, đầu tư công, mức độ xã hội hóa, tiêu chuẩn cơ sở vật chất, chính sách đào tạo, đãi ngộ, bảo hiểm, y học thể thao và chuyển đổi nghề nghiệp cho vận động viên.\r\n\r\nTrong các nhiệm vụ được nêu, Tổng Bí thư nhấn mạnh phát triển thể thao đại chúng là nhiệm vụ trung tâm, bao trùm và lâu dài. Theo đó, phải bảo đảm mọi người dân đều có quyền, có điều kiện và có động lực tham gia rèn luyện.\r\n\r\n\"Phải làm sao để thể dục thể thao thật sự đi vào từng gia đình, từng khu dân cư, từng trường học, từng cơ quan, từng nhà máy, từng doanh nghiệp, từng đơn vị lực lượng vũ trang, từng con người\", Tổng Bí thư nêu rõ.\r\n\r\nÔng đề nghị phát động phong trào mỗi người dân lựa chọn ít nhất một môn thể thao phù hợp để tập luyện thường xuyên. Các môn thể thao có thể rất đơn giản như đi bộ, chạy bộ, cầu lông, bóng chuyền, bơi, đạp xe, võ thuật, dưỡng sinh, yoga, cờ vua, cờ tướng... nhưng quan trọng là hình thành thói quen, biến việc rèn luyện thành nhu cầu tự thân và nếp sống hàng ngày.\r\n\r\nĐể thực hiện mục tiêu này, Tổng Bí thư yêu cầu quy hoạch quỹ đất cho thể thao cộng đồng, bảo đảm mỗi khu dân cư có không gian vận động; xây dựng sân chơi, bãi tập, công viên, đường đi bộ; đồng thời tận dụng hiệu quả trường học, nhà văn hóa, quảng trường và các không gian công cộng cho hoạt động thể dục thể thao.\r\n\r\nTổng Bí thư cũng nhấn mạnh việc nâng tầm giáo dục thể chất và thể thao học đường, coi đây là gốc rễ của chiến lược phát triển con người. Học sinh, sinh viên cần được vận động thực chất, được trang bị kỹ năng thể chất cơ bản và tiếp cận đa dạng các môn thể thao phù hợp, qua đó hình thành thói quen vận động, tinh thần kỷ luật và ý chí vượt khó.\r\n\r\nBên cạnh đó, ông đề nghị bảo tồn và phát triển các môn thể thao truyền thống dân tộc gắn với văn hóa cộng đồng, coi đây là tài sản quý cần được gìn giữ và phát huy trong đời sống hiện đại.\r\n\r\nĐối với thể thao thành tích cao, Tổng Bí thư yêu cầu phát triển theo hướng chuyên nghiệp, khoa học, trung thực và bền vững; xây dựng lộ trình đầu tư trọng điểm cho các môn có khả năng cạnh tranh; đổi mới cơ chế quản lý đội tuyển; tăng cường liên kết giữa thể thao học đường, thể thao phong trào và thể thao đỉnh cao, đồng thời bảo đảm đời sống và cơ hội chuyển đổi nghề nghiệp cho vận động viên sau thi đấu.\r\n\r\nTổng Bí thư cũng yêu cầu mở rộng cách tiếp cận về thể thao theo hướng toàn diện hơn, bao gồm cả vận động thể chất và vận động trí tuệ, nhằm xây dựng con người phát triển toàn diện cả về thể lực, trí lực và tinh thần.\r\n\r\nVề nguồn lực, ông nhấn mạnh phát triển thể dục thể thao không thể phụ thuộc hoàn toàn vào ngân sách nhà nước, cần đẩy mạnh xã hội hóa có định hướng, khuyến khích doanh nghiệp đầu tư vào cơ sở vật chất, công nghiệp và dịch vụ thể thao, khoa học thể thao và tổ chức sự kiện.\r\n\r\nCùng với đó, Việt Nam cần mở rộng hợp tác quốc tế, học hỏi kinh nghiệm về quản trị, huấn luyện và tổ chức, chủ động đăng cai các giải đấu phù hợp, từng bước nâng cao vị thế thể thao quốc gia trên trường quốc tế.\r\n\r\nKết thúc bài phát biểu, Tổng Bí thư Tô Lâm bày tỏ tin tưởng với truyền thống 80 năm, ngành thể dục thể thao Việt Nam sẽ tiếp tục phát triển mạnh mẽ, góp phần xây dựng con người Việt Nam phát triển toàn diện, nâng cao sức khỏe, tầm vóc, thể lực, trí lực và bản lĩnh trong giai đoạn mới.\r\n\r\n', 'assets/uploads/thumb_69c8215d322b61.85870512_small.webp', 'published', 5, '2026-03-29 01:43:41', '2026-03-30 03:17:26', 6, 1),
(6, 'Đường băng số 2 sân bay Phù Cát hoàn thành vào tháng 6', 'Tỉnh Gia Lai đang yêu cầu nhà thầu đẩy nhanh tiến độ thi công để hoàn thành đường băng số 2 sân bay Phù Cát vào tháng 6, phục vụ Năm du lịch quốc gia 2026 tại tỉnh này.\r\n\r\n', 'Sáng 27/3, ông Nguyễn Hữu Quế, Phó chủ tịch UBND tỉnh Gia Lai, cho biết một đường bằng tại sân bay Phù Cát không đủ điều kiện hạ tầng để đón các máy bay lớn từ các nước Đông Bắc Á, nên tỉnh đã đề nghị đầu tư đường băng số 2, khởi công xây dựng vào năm 2025, dự kiến khoảng tháng 6 -7 tới sẽ hoàn thành.\r\n\r\nSau khi đường băng số 2 khai thác, tỉnh có thể đón các máy bay lớn, sớm mở các đường bay charter (thuê chuyến) đưa khách quốc tế đến Gia Lai.\r\n\r\nLãnh đạo tỉnh Gia Lai tin tưởng sẽ bùng nổ lượng khách du lịch trong năm 2026. Tỉnh cũng sẽ tổ chức nhiều hoạt động trong Năm Du lịch Quốc gia 2026 tại địa phương.\r\n\r\nSân bay Phù Cát hiện được quy hoạch là sân bay nội địa, chưa được khai thác các đường bay thẳng quốc tế. Ông Võ Huy Cường, Phó tổng giám đốc Bamboo Airways, cho rằng dù là sân bay nội địa song sân bay Phù Cát có đủ điều kiện vẫn có thể phục vụ chuyến bay quốc tế. Ông đề nghị tỉnh mở luồng riêng tại nhà ga để phục vụ khách quốc tế, bổ sung khu vực xuất nhập cảnh, hải quan, kiểm dịch... giúp các hãng có thể đón khách quốc tế thuận lợi.\r\n\r\nMáy bay tại sân bay Phù Cát, tỉnh Gia Lai. Ảnh: Anh Duy\r\nMáy bay tại sân bay Phù Cát, tỉnh Gia Lai. Ảnh: Anh Duy\r\n\r\nÔng Cường cũng cho rằng, Gia Lai có hai sân bay là Phù Cát và Pleiku sẽ bổ trợ cho nhau, khi có sự cố ở một trong hai sân bay này thì hành khách vẫn có thể đến Gia Lai. Tuyến quốc lộ 19 kết nối giữa hai sân bay và phục vụ khách du lịch khám phá đa dạng các điểm du lịch tại vùng biển và cao nguyên.\r\n\r\nDự án đầu tư xây đường cất hạ cánh số 2 và các công trình đồng bộ tại Phù Cát có tổng mức đầu tư 3.010 tỷ đồng, do UBND tỉnh Bình Định là cơ quan chủ quản.\r\n\r\nTheo quy hoạch, đường băng số 2 chạy song song, cách đường băng hiện hữu 215 m về phía tây, dài 3.048 m, rộng 45 m. Đường băng mới khai thác các máy bay code C như A320/A321 và tương đương, có thể đón Boeing 787, 777, A350 khi có nhu cầu.\r\n\r\nThời kỳ 2021-2030 sân bay Phù Cát được quy hoạch công suất 5 triệu hành khách và 12.000 tấn hàng hóa mỗi năm. Giai đoạn này sẽ xây mới nhà ga hành khách T3 công suất khoảng 3,5 triệu hành khách/năm.\r\n\r\nĐến năm 2050, sân bay đạt công suất 7 triệu hành khách và 27.000 tấn hàng hóa mỗi năm, khai thác máy bay code C và tương đương. Giai đoạn này sẽ mở rộng nhà ga hành khách T3 để nâng công suất 7 triệu hành khách.\r\n\r\n', 'assets/uploads/thumb_69c821c66e3782.78781316_small.webp', 'published', 4, '2026-03-29 01:45:26', '2026-03-30 01:24:02', 3, 1),
(7, 'Đề xuất phụ thu nhiên liệu, vé máy bay nội địa có thể tới 4,68 triệu đồng', 'Cục Hàng không Việt Nam đề xuất áp dụng phụ thu nhiên liệu bay nội địa từ 1/4 đến 30/6, mức cao nhất 680.000 đồng/vé, trong bối cảnh giá Jet A1 tăng mạnh do căng thẳng Trung Đông.\r\n\r\n', 'Cục Hàng không Việt Nam vừa đề xuất Bộ Xây dựng cơ chế phụ thu nhiên liệu hàng không đối với vé nội địa hạng phổ thông cơ bản, áp dụng trong 3 tháng. Phụ thu được tính theo chi phí nhiên liệu thực tế và nằm ngoài mức giá trần hiện hành.\r\n\r\nTheo cơ quan này, giá nhiên liệu Jet A1 bình quân tháng 3 ở mức 190 - 200 USD/thùng và đã lên 234,3 USD/thùng vào ngày 24/3. Mức phụ thu vật lý cũng tăng lên trên 30 USD/thùng.\r\n\r\nVới đường bay 500 - 850 km, tương đương chặng Hà Nội - Đà Nẵng, phụ thu dự kiến 297.000 đồng/vé khi giá Jet A1 ở mức 220 USD/thùng, nâng giá vé tối đa từ 2,89 triệu đồng lên 3,16 triệu đồng. Nếu giá nhiên liệu từ 250 USD/thùng trở lên, phụ thu tăng lên 365.000 đồng, giá vé tối đa khoảng 3,255 triệu đồng.\r\n\r\nVới chặng 1.000 - 1.280 km như Hà Nội - TP HCM, phụ thu là 450.000 đồng/vé ở mức giá 220 USD/thùng và 553.000 đồng nếu trên 250 USD/thùng. Giá vé trần 3,4 triệu đồng có thể tăng lên gần 4 triệu đồng.\r\n\r\nChặng trên 1.280 km như Hà Nội - Phú Quốc có mức phụ thu 553.000 - 680.000 đồng/vé. Giá vé tối đa từ 4 triệu đồng có thể tăng lên 4,55 - 4,68 triệu đồng.\r\n\r\nCục Hàng không Việt Nam cho biết mức phụ thu đề xuất thấp hơn một số đường bay quốc tế tương đương. Ví dụ, chặng Nhật Bản - Hàn Quốc khoảng 2 giờ bay có phụ thu 55 USD khi giá nhiên liệu 180 USD/thùng, chênh lệch 40 USD so với mức 90 USD/thùng, tương đương khoảng 1,1 triệu đồng.\r\n\r\nĐề xuất phụ thu nhiên liệu, vé máy bay nội địa cao nhất 4,68 triệu đồng/vé\r\nÁp lực nhiên liệu tăng cao khiến từ tháng 4, các hãng hàng không trong nước dự kiến cắt giảm một số đường bay và tải cung ứng, ưu tiên duy trì các trục chính như Hà Nội - Đà Nẵng - TP HCM và các đường bay phục vụ nhiệm vụ chính trị, kinh tế - xã hội.\r\n\r\nMột số hãng đã giảm tần suất hoặc dừng khai thác các đường bay nội địa có hệ số sử dụng ghế thấp, chủ yếu vào khung giờ đêm, thấp điểm hoặc các đường bay ngách. Trên các đường bay quốc tế, nhiều hãng cũng đã lên kế hoạch phụ thu nhiên liệu.\r\n\r\nCục Hàng không ước tính trong trường hợp mức giá Jet A1 dao động quanh 200 USD/thùng, tăng cao gấp đôi so với trước chiến sự, chi phí hoạt động của các hãng bay sẽ phát sinh thêm 40%.\r\n\r\nTheo khảo sát gần 40 hãng hàng không quốc tế và khu vực, hơn 60% hãng đã hoặc dự kiến tăng phụ thu nhiên liệu hoặc điều chỉnh giá vé từ giữa tháng 3 để bù đắp chi phí.\r\n\r\nCục Hàng không Việt Nam kiến nghị Bộ Xây dựng báo cáo Chính phủ cho phép áp dụng cơ chế phụ thu linh hoạt theo giá Jet A1; gia hạn thuế nhập khẩu 0%, giảm thuế bảo vệ môi trường từ 1.500 đồng/lít xuống 1.000 đồng/lít và giảm thuế giá trị gia tăng đối với nhiên liệu bay để giảm áp lực tài chính cho doanh nghiệp.\r\n\r\n', 'assets/uploads/thumb_69c822c66fb9b2.90802192_small.webp', 'published', 4, '2026-03-29 01:49:42', '2026-03-30 01:25:04', 4, 1),
(8, 'Việt Nam khai trương đại sứ quán tại Ireland', 'Đại sứ quán Việt Nam tại Ireland được khai trương nhân kỷ niệm 30 năm thiết lập quan hệ ngoại giao giữa hai nước, khẳng định cam kết thúc đẩy hợp tác giữa hai bên.\r\n\r\n', 'Tại lễ khai trương đại sứ quán Việt Nam tại Dublin, Ireland chiều 26/3, Thứ trưởng Ngoại giao Lê Thị Thu Hằng nhấn mạnh đây là cột mốc quan trọng khi hai nước kỷ niệm 30 năm thiết lập quan hệ ngoại giao, mở ra chương mới trong quan hệ song phương, theo Bộ Ngoại giao.\r\n\r\nSự kiện này khẳng định cam kết thúc đẩy hợp tác toàn diện từ chính trị, thương mại đến giáo dục, khoa học - công nghệ, văn hóa và giao lưu nhân dân giữa hai nước, bà Hằng nói.\r\n\r\nĐại diện Việt Nam và Ireland cắt băng khai trương đại sứ quán Việt Nam tại Dublin ngày 26/3. Ảnh: Bộ Ngoại giao\r\nĐại diện Việt Nam và Ireland cắt băng khai trương đại sứ quán Việt Nam tại Dublin ngày 26/3. Ảnh: Bộ Ngoại giao\r\n\r\nSự kiện cũng thể hiện sự quan tâm của Đảng và Nhà nước đối với cộng đồng người Việt tại Ireland, đồng thời thực hiện cam kết từ chuyến thăm cấp nhà nước của Tổng Bí thư, Chủ tịch nước Tô Lâm hồi tháng 10/2024.\r\n\r\nTrong chuyến thăm, hai bên đã ra Tuyên bố chung về thúc đẩy quan hệ hợp tác Việt Nam - Ireland, đề ra định hướng hợp tác trên lĩnh vực chính trị - ngoại giao, an ninh, giáo dục - đào tạo, thương mại, đầu tư, hợp tác phát triển và các lĩnh vực tiềm năng khác, trong đó chú trọng giáo dục, nông nghiệp, phát triển kinh tế xã hội vùng sâu vùng xa và khắc phục hậu quả bom mìn.\r\n\r\nTại lễ khai trương đại sứ quán, Quốc vụ khanh Ireland Neale Richmond phụ trách Phát triển quốc tế và Kiều dân bày tỏ vui mừng trước sự phát triển mạnh mẽ của quan hệ song phương. Ông nhấn mạnh việc khai trương đại sứ quán là minh chứng rõ nét cho mối quan hệ ngày càng gắn bó sau chuyến thăm của Tổng bí thư Tô Lâm, cũng như cam kết chung trong thúc đẩy hợp tác trên các lĩnh vực.\r\n\r\nĐại sứ Việt Nam tại Ireland Phạm Toàn Thắng cho hay đại sứ quán sẽ mở rộng hoạt động ngoại giao, hỗ trợ kết nối kinh doanh, giáo dục và phục vụ cộng đồng người Việt hiệu quả, thiết thực hơn.\r\n\r\nIreland hiện là đối tác thương mại lớn thứ sáu của Việt Nam tại thị trường Liên minh châu Âu, với tổng kim ngạch thương mại hai chiều năm 2024 đạt 3,5 tỷ USD. Hai bên phấn đấu nâng kim ngạch thương mại song phương lên 5 tỷ USD vào năm 2026.\r\n\r\nNước này hiện có 41 dự án đầu tư tại Việt Nam với tổng số vốn đăng ký hơn 44 triệu USD, đứng thứ 61/141 quốc gia và vùng lãnh thổ có đầu tư tại Việt Nam.\r\n\r\nIreland coi Việt Nam là đối tác ưu tiên trong chính sách hợp tác phát triển, tập trung vào các lĩnh vực giáo dục, bình đẳng giới, ứng phó biến đổi khí hậu, hỗ trợ người dân tộc thiểu số; tiếp tục duy trì cung cấp ODA không hoàn lại cho Việt Nam trong các lĩnh vực xóa đói giảm nghèo, giáo dục đào tạo, hỗ trợ người khuyết tật, rà phá bom mìn...\r\n\r\n', 'assets/uploads/thumb_69c8243de7e927.34086124_small.webp', 'published', 3, '2026-03-29 01:55:58', '2026-03-30 01:19:25', 5, 2),
(9, 'Tổng thống Iran nêu điều kiện đàm phán hòa bình', 'Tổng thống Iran điện đàm với Thủ tướng Pakistan, nước trung gian đàm phán với Mỹ, cho hay các bên cần có sự tin tưởng nhau để thảo luận về chấm dứt xung đột.\r\n\r\n', 'Tổng thống Iran Masoud Pezeshkian đã nêu điều kiện đàm phán với Mỹ trong cuộc điện đàm kéo dài một giờ ngày 28/3 với Thủ tướng Pakistan Shehbaz Sharif, theo Văn phòng Thủ tướng Pakistan.\r\n\r\nÔng Pezeshkian trân trọng nỗ lực ngoại giao của Pakistan khi làm trung gian để tìm cách chấm dứt xung đột giữa Iran với Mỹ. Tổng thống Iran nhấn mạnh sự tin tưởng lẫn nhau giữa các bên là yếu tố cốt lõi để tạo thuận lợi cho các cuộc đàm phán, hướng tới hòa giải xung đột ở Trung Đông.\r\n\r\nTổng thống Pezeshkian là lãnh đạo cấp cao nhất của Iran tới nay đề cập đến khả năng đàm phán nhằm chấm dứt xung đột. Trước đó, các quan chức Iran tuyên bố sẽ không đàm phán và chiến sự sẽ chỉ kết thúc khi họ muốn vậy.\r\n\r\nHai lãnh đạo cũng đã thảo luận về tình hình thù địch trong khu vực cũng như giải pháp nhằm chấm dứt xung đột. Thủ tướng Sharif tái khẳng định Pakistan lên án mạnh mẽ các cuộc tấn công đang tiếp diễn của Israel vào Iran, bày tỏ sự đoàn kết và ủng hộ với nhân dân Iran trong thời điểm khó khăn này.\r\n\r\nThủ tướng Pakistan thông báo cho Tổng thống Pezeshkian về những nỗ lực tiếp xúc ngoại giao đang được ông cùng Ngoại trưởng Ishaq Dar và tư lệnh quân đội Asim Munir tiến hành nhằm kết nối với Mỹ cùng các quốc gia Hồi giáo và vùng Vịnh, qua đó tạo môi trường thuận lợi cho các cuộc đàm phán hòa bình.\r\n\r\nTổng thống Iran Masoud Pezeshkian phát biểu tại Tehran ngày 21/2. Ảnh: Văn phòng Tổng thống Iran\r\n\r\nTổng thống Iran Masoud Pezeshkian phát biểu tại Tehran ngày 21/2. Ảnh: Văn phòng Tổng thống Iran\r\n\r\nPakistan sắp chủ trì hội nghị 4 bên giữa ngoại trưởng các nước Pakistan, Arab Saudi, Thổ Nhĩ Kỳ và Ai Cập tại thủ đô Islamabad trong hai ngày 29-30/3 để bàn về nỗ lực đàm phán chấm dứt xung đột Iran.\r\n\r\nPakistan đang nổi lên như một bên trung gian hòa giải then chốt giữa Iran và Mỹ khi cuộc xung đột kéo dài sang tháng thứ hai. Islamabad vốn có quan hệ lâu đời với Tehran cũng như có nhiều mối liên hệ chặt chẽ tại vùng Vịnh, trong khi Thủ tướng Sharif và tướng Munir cũng tạo dựng được mối quan hệ cá nhân tốt đẹp với Tổng thống Mỹ Donald Trump.\r\n\r\nNgoại trưởng Thổ Nhĩ Kỳ Hakan Fidan tối 27/3 tiết lộ hội nghị vốn dự kiến tổ chức tại Thổ Nhĩ Kỳ nhưng \"vì các đồng nghiệp Pakistan của chúng tôi phải ở lại trong nước, chúng tôi đã chuyển địa điểm sang Pakistan\".\r\n\r\nÔng cho hay cuộc họp sẽ tìm cách thiết lập một cơ chế nhằm giảm leo thang căng thẳng trong chiến sự Iran. \"Chúng tôi sẽ thảo luận về hướng đi của các cuộc đàm phán trong cuộc chiến này, cách 4 quốc gia đánh giá tình hình và những việc có thể làm\".\r\n\r\nCuộc chiến giữa Mỹ - Israel với Iran đã bước sang tháng thứ hai, khiến hơn 3.000 người thiệt mạng và làm đảo lộn nền kinh tế toàn cầu. Các nỗ lực ngoại giao đang được thúc đẩy nhằm kết thúc chiến sự, sau khi Tổng thống Trump thông báo hoãn kế hoạch không kích các nhà máy điện của Iran.\r\n\r\n', 'assets/uploads/thumb_69c82468ad1259.45200532_small.webp', 'published', 3, '2026-03-29 01:56:40', '2026-03-30 01:23:20', 6, 2),
(10, 'Lãnh đạo Vatican lần đầu thăm Monaco sau gần 500 năm', 'Giáo hoàng Leo XIV tới Monaco, nơi có biệt danh \"sân chơi của các tỷ phú\", đánh dấu chuyến thăm đầu tiên của một lãnh đạo Vatican tới quốc gia này sau 488 năm.\r\n\r\n', 'Giáo hoàng Leo XIV ngày 28/3 ngồi trực thăng tới Monaco, quốc gia ven biển Địa Trung Hải có diện tích nhỏ thứ hai thế giới, chỉ lớn hơn Vatican, bắt đầu chuyến thăm một ngày. Monaco, quốc gia nổi tiếng với sòng bạc, du thuyền sang trọng và nhà hàng cao cấp, được Giáo hoàng chọn là điểm công du đầu tiên ở châu Âu kể từ khi ông nhậm chức hồi tháng 5/2025.\r\n\r\nĐây cũng là chuyến thăm Monaco đầu tiên của người đứng đầu Vatican sau 488 năm, từ khi Giáo hoàng Paul III tới quốc gia này vào năm 1538.\r\n\r\nTại Monte Carlo, biển quảng cáo in hình Giáo hoàng Leo XIV mặc trang phục trắng giản dị tương phản rõ nét với những chiếc xe thể thao bóng loáng và dòng khách du lịch tấp nập mà nhiều người trong số này thậm chí không biết về chuyến thăm của Giáo hoàng.\r\n\r\nGiáo hoàng Leo XIV vẫy chào giáo dân tại Giáo xứ Thánh Tâm Chúa Jesus, Rome trong chuyến thăm mục vụ ngày 15/3. Ảnh: AFP\r\n\r\nGiáo hoàng Leo XIV vẫy chào giáo dân tại Giáo xứ Thánh Tâm Chúa Jesus, Rome trong chuyến thăm mục vụ ngày 15/3. Ảnh: AFP\r\n\r\nBà Isabel Fissore, 62 tuổi, chủ một cửa hàng trang sức nhỏ, phấn khích khi hay tin về chuyến thăm của Giáo hoàng tới Monaco.\r\n\r\n\"Đây là một sự kiện lịch sử, khi hai quốc gia nhỏ nhất hành tinh cùng nhau lan tỏa thông điệp về hòa bình, ánh sáng và tình yêu thương ra khắp thế giới\", bà nói. \"Chúng tôi có thể là một quốc gia nhỏ, nhưng có tấm lòng bao dung rộng lớn\".\r\n\r\nMonaco là một trong số ít nơi ở châu Âu duy trì Công giáo là quốc giáo và có mối quan hệ ngoại giao lâu đời với Tòa thánh. Công quốc này có diện tích khoảng 2 km2, dân số gần 40.000 người, là nơi được mệnh danh \"sân chơi của các tỷ phú\". Nhà thờ là một trong số ít nơi ở Monaco mà các tỷ phú, lao công và công nhân xây dựng có thể ngồi cùng nhau.\r\n\r\nĐây là nơi Giáo hoàng Leo XIV sẽ tiếp xúc với \"nhiều nền văn hóa, quốc gia, nguồn gốc và ngôn ngữ khác nhau\", Tổng giám mục Monaco Dominique-Marie David phát biểu trong cuộc họp báo hôm 27/3.\r\n\r\nLực lượng an ninh vào vị trí trước khi Giáo hoàng Leo XIV đến sân bay trực thăng Monaco ở Monte Carlo, Monaco, ngày 28/3. Ảnh: AP\r\nLực lượng an ninh vào vị trí trước khi Giáo hoàng Leo XIV đến sân bay trực thăng Monaco ở Monte Carlo, Monaco, ngày 28/3. Ảnh: AP\r\n\r\n\"Các chuyến công du của Đức Thánh Cha luôn có tầm ảnh hưởng vượt biên giới, vì vậy ngài biết rằng Monaco có thể đóng vai trò như một diễn đàn nhỏ để gửi thông điệp tới toàn thế giới\", ông nói thêm.\r\n\r\nGiáo hoàng Leo XIV sẽ gặp Thân vương Monaco Albert II, gặp gỡ cộng đồng Công giáo tại Nhà thờ Đức Mẹ Vô nhiễm Nguyên tội, sau đó tới quảng trường trước Nhà thờ Thánh Devota, vị thánh bảo hộ của Monaco. Điểm nhấn của chuyến thăm sẽ là thánh lễ ngoài trời tại Sân vận động Louis II, dự kiến có 15.000 người tham dự.\r\n\r\nNgười phát ngôn Vatican Matteo Bruni cho biết trong chuyến thăm Monaco, Giáo hoàng dự kiến thảo luận về môi trường, vấn đề mà Thân vương Albert II rất quan tâm, cũng như \"bảo vệ sự sống dưới mọi hình thức\", gồm chống phá thai và chống trợ tử, kêu gọi chấm dứt xung đột, trong bối cảnh cuộc chiến Iran đã bước sang tháng thứ hai.\r\n\r\nJoelle Burgagni, sinh viên 20 tuổi người Italy ở Monaco, hy vọng \"nhận được lời khuyên\" từ Giáo hoàng về thực hành đức tin. \"Chuyến thăm này mang lại cho tôi rất nhiều cảm xúc và năng lượng\", cô nói.\r\n\r\n', 'assets/uploads/thumb_69c824967f97c4.91953800_small.webp', 'published', 8, '2026-03-29 01:57:26', '2026-03-30 04:04:59', 3, 2),
(11, 'Bi kịch của lao động nhập cư giữa xung đột Trung Đông', 'Chiếm hơn 30% dân số vùng Vịnh, lao động nhập cư từ Nam Á đang trở thành nhóm dễ bị tổn thương khi xung đột Iran gây tổn thất lớn cho khu vực.\r\n\r\n', 'Một tuần sau khi Mỹ - Israel tập kích Iran và Tehran phát động chiến dịch đáp trả khắp vùng Vịnh, ông Jaya Khuntia gọi điện cho con trai là Kuna, đang làm việc ở Doha, Qatar vào 22h ngày 6/3.\r\n\r\nGia đình ông Khuntia, hiện sống ở ngôi làng Naikanipalli thuộc bang Odisha, miền đông Ấn Độ, đang rất lo lắng cho người con trai đang làm xa nhà.\r\n\r\n\"Nó bảo tôi rằng \'con ở đây an toàn, bố đừng lo\'\", ông nhớ lại cuộc trò chuyện với Kuna.\r\n\r\nÔng Jaya Khuntia cùng gia đình ở bang Odisha, miền đông Ấn Độ. Ảnh: Al Jazeera\r\nÔng Jaya Khuntia cùng gia đình ở bang Odisha, miền đông Ấn Độ. Ảnh: Al Jazeera\r\n\r\nĐó cũng là lần cuối cùng họ nói chuyện với nhau. Hôm sau, gia đình ông Khuntia nhận được điện thoại từ bạn cùng phòng của Kuna, báo tin anh đã đột tử vì lên cơn đau tim, sau khi nghe tiếng tên lửa và các mảnh vỡ rơi từ vụ đánh chặn gần nơi ở. Thi thể của anh được đưa về quê nhà vài ngày sau đó.\r\n\r\nGia đình của chàng trai 25 tuổi này, vốn làm thợ lắp ống nước tại thủ đô Qatar, nằm trong số hàng triệu người khắp Nam Á đang chịu ảnh hưởng trực tiếp từ cuộc chiến ở Trung Đông.\r\n\r\nKhoảng 21 triệu lao động nhập cư Nam Á đang làm việc tại các quốc gia vùng Vịnh, chiếm hơn 30% tổng dân số khu vực. Đối với các gia đình lao động nhập cư ở quê nhà, sự an toàn của người thân và cả những giấc mơ của họ đều bị đe dọa.\r\n\r\nGia đình ông Khuntia đã vay nợ 300.000 rupee (khoảng 3.200 USD) vào năm 2025 để lo đám cưới cho hai cô con gái. Kuna đi làm tại Doha từ cuối năm 2025 với mức thu nhập 35.000 rupee (372 USD) mỗi tháng. Anh trích khoảng 15.000 rupee trong đó gửi về nhà để giúp bố mẹ trả nợ.\r\n\r\n\"Chúng tôi cứ ngỡ những khổ cực cuối cùng cũng chấm dứt. Đứa con trai duy nhất của tôi thường bảo \'cha đừng lo, có con ở đây rồi\'. Nó là niềm hy vọng duy nhất, là tất cả của chúng tôi\", ông Khuntia nói.\r\n\r\nNiềm hy vọng của gia đình đã vụt tắt. \"Cuộc điện đó đã kết thúc tất cả. Nó hứa sẽ trở về sau khi trả hết nợ, nhưng giờ lại về trong chiếc quan tài. Giờ chúng tôi chẳng còn gì cả. Mất con trai chính là nỗi đau lớn nhất mà chúng tôi phải mang theo suốt đời\", ông nói.\r\n\r\nMáy bay sắp hạ cánh giữa cột khói bốc lên từ đám cháy gần Sân bay Quốc tế Dubai hôm 16/3. Ảnh: AFP\r\nMáy bay sắp hạ cánh giữa cột khói bốc lên từ đám cháy gần Sân bay Quốc tế Dubai hôm 16/3. Ảnh: AFP\r\n\r\n6 nước vùng Vịnh gồm Bahrain, Kuwait, Oman, Qatar, Arab Saudi và UAE, có tổng 35 triệu người nước ngoài. Trong số đó, 9 triệu người đến từ Ấn Độ, 5 triệu người Pakistan, 5 triệu người Bangladesh, 1,2 triệu người Nepal và khoảng 650.000 người từ Sri Lanka.\r\n\r\nHầu hết họ làm các công việc chân tay, xây dựng hoặc hỗ trợ các ngành công nghiệp và dịch vụ cốt lõi cho sự thịnh vượng của vùng Vịnh. Nhưng kể từ khi xung đột bùng phát, những lao động nhập cư này nằm trong nhóm dễ bị tổn thương nhất.\r\n\r\nCác nhà máy lọc dầu, công trường xây dựng, sân bay và bến cảng, nơi vốn có nhiều lao động nhập cư làm việc, đều là mục tiêu hàng đầu trong các cuộc tấn công của Iran. Tình trạng đình chỉ hoạt động tại nhiều cơ sở trong số này cùng nỗi lo suy thoái kinh tế nghiêm trọng trong khu vực đã khiến nhiều lao động và gia đình họ lo lắng.\r\n\r\nHamza, lao động Pakistan làm việc tại một cơ sở dầu mỏ ở UAE, vẫn thấy sợ hãi khi nhớ lại cuộc tấn công mà anh chứng kiến gần đây.\r\n\r\n\"Chiếc máy bay không người lái (UAV) đâm vào nhà kho ngay trước mặt chúng tôi. Mọi người đều hoảng loạn. Hầu hết người ở đó đến từ Ấn Độ, Pakistan và Bangladesh\", anh nói. \"Sau đó chúng tôi bị mất ngủ nhiều đêm. Chiếc UAV ở khoảng cách gần tới mức suýt giết chết chúng tôi. Trong một khoảnh khắc, tôi đã nghĩ mình sẽ là người tiếp theo\".\r\n\r\nBất chấp những rủi ro đó, Hamza cho biết anh không thể rời đi. \"Chúng tôi muốn quay về, nhưng không thể. Cả gia đình phụ thuộc vào chúng tôi. Ở đây nguy hiểm, nhưng nếu chúng tôi ngừng làm việc, họ sẽ không có gì để ăn. Chúng tôi không còn lựa chọn nào khác\", anh nói.\r\n\r\nImran Khan, giảng viên tại Viện Quản lý New Delhi và chuyên nghiên cứu về kinh tế di cư, cho biết lao động nhập cư từ Nam Á nhận việc ở Trung Đông vì coi đây là lối thoát kinh tế duy nhất. Các nước phương Tây trong những năm gần đây đã tăng rào cản nhập cảnh đối với lao động chân tay nước ngoài có trình độ học vấn thấp.\r\n\r\n\"Những lao động này là nhóm chịu ảnh hưởng nặng nề nhất trong các cuộc khủng hoảng, dù là chiến tranh hay thiên tai\", ông nói. \"Tôi đã trò chuyện với nhiều lao động nhập cư, đặc biệt là người Ấn Độ ở Trung Đông, và biết nhiều người đang sống trong cảnh khốn khổ kể từ khi xung đột bắt đầu\".\r\n\r\nNhưng cũng giống như Hamza, hầu hết họ không thể rời đi.\r\n\r\n\"Họ không thể bỏ việc, bởi điều đó đồng nghĩa lập tức mất nguồn thu nhập và cơ hội ở quê nhà thì quá hạn chế. Họ phải nuôi gia đình và nếu không có công việc này, cuộc sống sẽ trở nên rất khốn khó\", ông nói.\r\n\r\nCác quốc gia Trung Đông cũng là nguồn kiều hối chính cho các quốc gia Nam Á như Ấn Độ, Pakistan, Bangladesh, Sri Lanka và Nepal. Số tiền kiều hối mà 5 quốc gia này nhận được từ khu vực là 103 tỷ USD, tương đương với tổng sản phẩm quốc nội (GDP) của Oman.\r\n\r\nLượng kiều hối mà Ấn Độ nhận được từ vùng Vịnh là 50 tỷ USD, lớn hơn toàn bộ GDP của Bahrain. Pakistan nhận được 38,3 tỷ USD kiều hối, Bangladesh 13,5 tỷ USD, Sri Lanka 8 tỷ USD và Nepal 5 tỷ USD.\r\n\r\nNgười đi đường nhìn khói bốc lên sau vụ đánh chặn ở khu công nghiệp Al Quoz ở Dubai, UAE ngày 13/3. Ảnh: AP\r\nMột số người đứng nhìn khói bốc lên sau vụ đánh chặn ở khu công nghiệp Al Quoz ở Dubai, UAE ngày 13/3. Ảnh: AP\r\n\r\nVới xung đột leo thang gần đây ở Trung Đông, giới chuyên gia cảnh báo nguồn kiều hối này có thể bị ảnh hưởng đáng kể, đặc biệt nếu nền kinh tế vùng Vịnh bị suy yếu và lao động bị sa thải.\r\n\r\n\"Kiều hối là trụ cột quan trọng đối với Pakistan và các nền kinh tế Nam Á khác, và một phần lớn đến từ Trung Đông\", Faisal Abbas, chuyên gia kinh tế quốc tế và giám đốc tại Trung tâm Xuất sắc về Nghiên cứu Dân số và An sinh tại Pakistan, nói.\r\n\r\nTuy nhiên, trước diễn biến khó lường của xung đột hiện tại, vẫn có một số lao động Nam Á lên kế hoạch trở về quê. Noor, lao động nhập cư từ Bangladesh đang làm việc tại một cơ sở dầu mỏ ở Arab Saudi, kể đã chứng kiến các cuộc tấn công bằng UAV và \"nỗi sợ đó cứ đeo bám tôi\".\r\n\r\nGia đình anh cũng rất lo lắng. \"Các con khóc mỗi khi gọi điện cho tôi. Chúng sợ tôi mất mạng ở đây\", anh nói.\r\n\r\nAnh hiểu rằng việc trở về Bangladesh đồng nghĩa với việc gia đình sẽ gặp nhiều khó khăn hơn, nhưng anh đã quyết định sẽ về ngay khi hết hạn hợp đồng.\r\n\r\n\"Tôi thà quay về và vật lộn để sinh tồn cùng gia đình còn hơn là sống ở đây trong nỗi sợ hãi thường trực. Ít nhất ở đó, tôi sẽ được ở bên họ\", anh nói.\r\n\r\n', 'assets/uploads/thumb_69c824fca496a1.30628118_small.webp', 'published', 4, '2026-03-29 01:59:09', '2026-03-30 01:18:46', 4, 2),
(12, 'Phó tổng thống Mỹ đặc biệt quan tâm đến UFO', 'Phó tổng thống Mỹ Vance cho biết ông đặc biệt quan tâm đến UFO và cam kết đi sâu tìm hiểu tài liệu của chính phủ liên quan vấn đề này.\r\n\r\n', '\"Tôi chưa đủ thời gian để thực sự hiểu rõ vật thể bay không xác định (UFO), nhưng tôi sẽ làm, hãy tin tôi. Tôi bị ám ảnh bởi vấn đề này\", Phó tổng thống Mỹ JD Vance bật cười khi nói với người dẫn chương trình Benny Johnson hôm 27/3, khi được hỏi về sắc lệnh của Tổng thống Donald Trump hồi tháng 2.\r\n\r\nSắc lệnh này yêu cầu các cơ quan liên quan bắt đầu \"xác định và công bố\" tài liệu của chính phủ liên quan UFO và người ngoài hành tinh.\r\n\r\n\"Tôi vẫn còn ba năm nữa trên cương vị phó tổng thống. Tôi sẽ làm rõ mọi thứ liên quan đến các hồ sơ UFO\", ông Vance nói thêm.\r\n\r\nPhó tổng thống Mỹ JD Vance tại Nhà Trắng ngày 27/3. Ảnh: AP\r\n\r\nPhó tổng thống Mỹ JD Vance tại Nhà Trắng ngày 27/3. Ảnh: AP\r\n\r\nTổng thống Trump trước đó cho biết sắc lệnh được đưa ra \"dựa trên sự quan tâm lớn của công chúng\". Động thái của chính quyền Trump diễn ra cùng tháng cựu tổng thống Barack Obama nói rằng người ngoài hành tinh \"có thật\", dù ông chưa từng thấy họ.\r\n\r\nLiên quan phát biểu của ông Obama, ông Trump nói với phóng viên rằng cựu tổng thống đã \"tiết lộ thông tin mật, điều mà ông ấy không nên làm\".\r\n\r\nSau khi các phát biểu gây xôn xao trên mạng, ông Obama đính chính thông điệp của mình qua bài đăng trên Instagram. Cựu tổng thống Mỹ lập luận rằng vũ trụ rộng lớn khiến khả năng có sự sống ở nơi khác là cao, song khoảng cách giữa các hệ sao quá xa nên khả năng con người đã được người ngoài hành tinh ghé thăm là thấp và ông không thấy bằng chứng nào trong nhiệm kỳ cho thấy đã có tiếp xúc với các nền văn minh ngoài Trái Đất.\r\n\r\nTrong cuộc trao đổi với Johnson, Phó tổng thống Vance đưa ra một góc nhìn mang màu sắc tôn giáo. \"Tôi không nghĩ họ là người ngoài hành tinh. Tôi tin đó là ác quỷ\", ông nói, đồng thời mô tả đây là cách hiểu của Kitô giáo về \"những thực thể siêu nhiên thường xuất hiện trên bầu trời và có những tác động kỳ lạ lên con người\".\r\n\r\nMối quan tâm đến UFO và các hiện tượng liên quan đã gia tăng trở lại những năm gần đây, khi chính phủ Mỹ điều tra nhiều báo cáo về vật thể bay được cho là \"siêu nhiên\", trong bối cảnh lo ngại đối thủ có thể đang thử nghiệm những công nghệ quân sự tiên tiến.\r\n\r\nVào tháng 3/2024, Lầu Năm Góc công bố báo cáo nêu rằng không có bằng chứng cho thấy các hiện tượng trên không chưa xác định là công nghệ của người ngoài hành tinh. Nhiều trường hợp nghi vấn thực chất chỉ là khinh khí cầu thời tiết, máy bay do thám, vệ tinh hoặc các hoạt động bình thường khác.\r\n\r\n', 'assets/uploads/thumb_69c82559b3b263.03009123_small.webp', 'published', 5, '2026-03-29 02:00:42', '2026-03-30 02:45:21', 5, 2),
(13, 'Houthi tham chiến, phóng tên lửa vào Israel', 'Quân đội Israel phát hiện và đánh chặn tên lửa đầu tiên phóng từ Yemen, khi Houthi, đồng minh của Iran, bắt đầu tham chiến để ủng hộ Tehran.\r\n\r\n', 'Còi báo động vang lên ở Beersheba và các thị trấn lân cận tại miền nam Israel vào sáng sớm 28/3. Quân đội Israel sau đó thông báo \"xác định một vụ phóng tên lửa đạn đạo từ Yemen hướng về phía lãnh thổ Israel, các hệ thống phòng không đang hoạt động để đánh chặn mối đe dọa\".\r\n\r\nĐây là lần đầu tiên Israel ghi nhận tên lửa được phóng từ Yemen kể từ khi chiến sự Iran nổ ra ngày 28/2. Truyền thông Israel cho biết quả tên lửa đã bị đánh chặn và không gây thương vong hay thiệt hại.\r\n\r\nTên lửa Iran rạch ngang bầu trời thành phố Netanya, Israel trong đợt tập kích quy mô lớn ngày 28/3. Ảnh: AFP\r\n\r\nTên lửa bay ngang bầu trời thành phố Netanya, Israel ngày 28/3. Ảnh: AFP\r\n\r\nYemen là nơi Houthi, nhóm dân quân quyền lực được Iran hậu thuẫn, đang kiểm soát nhiều vùng lãnh thổ. Houthi từng đe dọa sẽ tấn công Israel kể từ khi chiến sự Iran bùng phát, nhưng chưa công khai thực hiện đòn tập kích nào.\r\n\r\n\"Chúng tôi đã tiến hành chiến dịch quân sự đầu tiên, phóng loạt tên lửa đạn đạo nhắm vào các cơ sở quân sự nhạy cảm của Israel\", Houthi sau đó ra tuyên bố. Nhóm này cho hay đây là phản ứng trực tiếp với \"hành động leo thang quân sự, nhắm mục tiêu vào hạ tầng cũng những tội ác chống lại anh em chúng tôi ở Lebanon, Iran, Iraq và Palestine\".\r\n\r\nThông tin này cho thấy Houthi đã bắt đầu tham chiến khi giao tranh giữa Mỹ - Israel với Iran bước sang tháng thứ hai. Houthi ngày 27/3 tuyên bố \"ngón tay đã đặt lên trên cò súng, sẵn sàng can thiệp quân sự trực tiếp\" nếu có thêm quốc gia tham gia chiến dịch của Mỹ - Israel nhằm vào Iran.\r\n\r\nHouthi từng phóng hàng chục tên lửa tấn công Israel và các tuyến giao thông hàng hải trên Biển Đỏ từ tháng 11/2023, nhằm thể hiện sự ủng hộ với nhóm Hamas ở Gaza, một phần trong \"Trục Kháng chiến\" được Iran hậu thuẫn. Các đòn tấn công này dừng lại sau khi Hamas và Israel đạt thỏa thuận ngừng bắn vào tháng 10/2025.\r\n\r\nTuy nhiên, giới quan sát lo ngại việc Houthi tham gia vào chiến sự Iran hiện nay có thể khiến tình hình leo thang theo hướng tồi tệ hơn. Trong một tháng qua, Iran gần như phong tỏa eo biển Hormuz, khiến nhiều hãng vận tải đường biển chuyển hướng sang Biển Đỏ để vận chuyển một phần dầu từ Arab Saudi.\r\n\r\nHouthi có thể bóp nghẹt dòng chảy hàng hóa qua biển Đỏ và một yết hầu khác là eo biển Bab el-Manded, tạo ra một điểm nghẽn năng lượng mới với thế giới.\r\n\r\nVị trí eo biển Bab el-Mandeb và đường ống dẫn dầu của Arab Saudi. Đồ họa: WSJ\r\n', 'assets/uploads/thumb_69c82594839405.28983484_small.webp', 'published', 6, '2026-03-29 02:01:40', '2026-03-30 03:01:56', 6, 2),
(14, 'Người giàu Mỹ cũng bất an về nền kinh tế', 'Niềm tin tiêu dùng của người Mỹ xuống thấp nhất 3 tháng, khi xung đột Trung Đông khiến giá xăng tăng vọt và chứng khoán sụt giảm.\r\n\r\n', 'Ngày 27/3, Đại học Michigan (Mỹ) công bố kết quả khảo sát niềm tin tiêu dùng trong nước tháng 3. Theo đó, số liệu này giảm về 53,3 điểm - thấp nhất kể từ tháng 12/2025. Mức này cũng thấp hơn dự báo của các nhà phân tích trong khảo sát của hãng dữ liệu FactSet trước đó.\r\n\r\n\"Niềm tin sụt giảm ở tất cả lứa tuổi và quan điểm chính trị. Giảm mạnh nhất là nhóm người tiêu dùng có thu nhập trung bình và cao, sở hữu tài sản chứng khoán, do giá xăng tăng vọt và thị trường tài chính biến động sau chiến sự\", Joanne Hsu - Giám đốc phụ trách khảo sát của Đại học Michigan nhận định.\r\n\r\nXung đột tại Trung Đông đang khiến giá dầu toàn cầu tăng hơn 50%, trong khi các chỉ số chứng khoán Mỹ giảm khoảng 6% trong một tháng qua. Nhà đầu tư ngờ vực khả năng cuộc chiến sớm kết thúc, dù Tổng thống Mỹ Donald Trump cho biết họ đang đàm phán với Iran.\r\n\r\nNhân viên xếp rau củ trong một siêu thị ở Washington (Mỹ). Ảnh: Reuters\r\n\r\nNhân viên xếp rau củ trong một siêu thị ở Washington (Mỹ). Ảnh: Reuters\r\n\r\nNếu chiến sự tại Trung Đông kéo dài nhiều tháng, triển vọng kinh tế có thể xấu đi nhanh chóng, tạo ra vòng xoáy suy giảm kinh tế. Thị trường chứng khoán đi xuống kéo theo chi tiêu yếu và cuối cùng sẽ gây ra suy thoái.\r\n\r\n\"Trong một nền kinh tế đi theo mô hình chữ K, tác động từ nhóm thu nhập cao có thể nhanh chóng lan rộng\", Heather Long - kinh tế trưởng tại Navy Federal Credit Union cảnh báo.\r\n\r\nKhảo sát cũng cho thấy người Mỹ dự báo lạm phát năm tới lên 3,8%. Tháng trước, họ chỉ kỳ vọng mức này là 3,4%. Dù vậy, họ không cho rằng lạm phát cao sẽ duy trì trong 5-10 năm tới.\r\n\r\nĐiều này phần nào trấn an Cục Dự trữ liên bang Mỹ (Fed). Cơ quan này theo dõi chặt kỳ vọng lạm phát của người dân, đặc biệt trong dài hạn, vì số liệu này phản ánh niềm tin của người Mỹ vào khả năng kiểm soát giá cả của Fed. Mục tiêu của cơ quan này là chỉ số chi tiêu cá nhân (PCE) chỉ tăng 2%. Số liệu này trong tháng 1 tăng 2,8%.\r\n\r\n\"Người tiêu dùng có thể không cho rằng các diễn biến tiêu cực gần đây kéo dài. Tuy nhiên, quan điểm này có thể thay đổi nếu xung đột Iran vẫn tiếp diễn hoặc giá năng lượng ảnh hưởng đến lạm phát chung\", Hsu nói.\r\n\r\nDù vậy, niềm tin tiêu dùng đi xuống không phải lúc nào cũng đồng nghĩa chi tiêu suy yếu. Chỉ số này từng xuống thấp kỷ lục năm 2022, khi lạm phát tại Mỹ lên cao nhất 40 năm. Niềm tin tiêu dùng cũng lao dốc năm 2023, khi Quốc hội Mỹ bế tắc về đàm phán trần nợ. Tuy nhiên, ở các giai đoạn đó, người Mỹ vẫn mở hầu bao.\r\n\r\nTiêu dùng hiện đóng góp hai phần ba quy mô kinh tế Mỹ. Hoạt động này chịu tác động mạnh hơn bởi thị trường lao động, ví dụ việc sa thải có tăng hay không. Năm ngoái, khi tăng trưởng việc làm yếu, số đơn xin trợ cấp thất nghiệp vẫn ở mức thấp nhất lịch sử.\r\n\r\nTừ giữa năm 2023, tăng trưởng lương tại Mỹ luôn cao hơn lạm phát, đồng nghĩa người tiêu dùng vẫn còn khả năng chi tiêu. Nhưng nếu hoạt động sa thải tăng và tìm việc làm khó hơn, họ buộc phải thắt hầu bao.\r\n\r\nThực tế, chi tiêu vài tháng gần đây có dấu hiệu yếu đi. Doanh số bán lẻ tháng 1 giảm 0,2%, sau khi đi ngang trong tháng 12/2025. Thời tiết lạnh giá được cho là nguyên nhân kìm hãm chi tiêu trong tháng đầu năm.\r\n\r\n', 'assets/uploads/thumb_69c95855026fc1.17474513_small.webp', 'published', 4, '2026-03-29 23:50:29', '2026-03-30 01:58:15', 3, 3),
(15, 'FLC tính làm loạt dự án 150.000 tỷ đồng ở Gia Lai', 'FLC đề xuất các dự án mở rộng sân bay, logistics, du lịch, khu đô thị... với tổng quy mô vốn 150.000 tỷ đồng ở Gia Lai sau khi ông Trịnh Văn Quyết tái xuất.\r\n\r\n', 'Ngày 28/3, trong khuôn khổ hội nghị xúc tiến đầu tư tỉnh Gia Lai, Tập đoàn FLC đã ký biên bản ghi nhớ (MOU) để nghiên cứu, đề xuất đầu tư loạt dự án quy mô lớn ở Gia Lai.\r\n\r\nCác dự án này gồm mở rộng sân bay, phát triển logistics, dịch vụ du lịch nghỉ dưỡng, khu đô thị với tổng vốn lên đến 150.000 tỷ đồng.\r\n\r\nĐồng thời, doanh nghiệp này cũng nhận chủ trương chủ trương đầu tư khu phức hợp Đak Đoa với tổng mức đầu tư 8.267 tỷ đồng. Theo kế hoạch, FLC dự kiến khởi công dự án này cuối tuần sau. Đây là một tổ hợp khách sạn nghỉ dưỡng, sân golf 36 hố, trung tâm hội nghị, giải trí với mục tiêu thu hút du khách từ các thị trường Đông Bắc Á (Trung Quốc, Hàn Quốc, Nhật Bản).\r\n\r\nCác động thái này được FLC triển khai ngay sau khi doanh nhân Trịnh Văn Quyết trở lại với vai trò Chủ tịch tập đoàn này sau 4 năm rời vị trí. Hôm 27/3, ông Quyết nói rằng với dự án ở Đăk Đoa, FLC đang thiết kế dòng sản phẩm mới với mục tiêu đem đến trải nghiệm thực sự khác lạ cho du khách khi đến với cao nguyên.\r\n\r\nTại hội nghị xúc tiến đầu tư, tỉnh Gia Lai đã trao quyết định chấp thuận chủ trương, giấy chứng nhận đăng ký đầu tư và ký kết các biên bản MOU cho 273 dự án. Tổng vốn đăng ký và dự kiến rót vào tỉnh khoảng 850.000 tỷ đồng, tương ứng 33 tỷ USD.\r\n\r\nTrong đó, 142 dự án được trao quyết định chấp thuận chủ trương có vốn đăng ký hơn 225.000 tỷ đồng. 131 dự án còn lại ký biên bản MOU với mức đầu tư dự kiến hơn 606.000 tỷ.\r\n\r\nSau hợp nhất cùng Bình Định, tỉnh Gia Lai mới có diện tích tự nhiên hơn 21.500 km2 - lớn thứ nhì cả nước, dân số 3,5 triệu người. Năm ngoái, GRDP của Gia Lai đạt 7,2%, quy mô GRDP gần 270.700 tỷ đồng. Tỉnh thu hút được 192 dự án đầu tư, trong đó gồm 16 dự án FDI với tổng vốn đăng ký khoảng 160.000 tỷ.\r\n\r\n', 'assets/uploads/thumb_69c958895f36b7.17249461_small.webp', 'published', 3, '2026-03-29 23:51:21', '2026-03-30 01:22:07', 4, 3);
INSERT INTO `article` (`article_id`, `title`, `summary`, `content`, `thumbnail`, `status`, `view_count`, `created_at`, `updated_at`, `user_id`, `category_id`) VALUES
(16, 'Nhà đầu tư mất ngủ hàng đêm vì chiến sự Trung Đông', 'Wang Yapei đã mạnh tay cắt giảm danh mục đầu tư khi làn sóng bán tháo lan ra khắp các thị trường toàn cầu do xung đột tại Trung Đông.\r\n\r\n', '\"Tôi không thích đi tàu lượn đâu. Phiên đầu tuần rất xấu, nên tôi giảm quy mô danh mục đầu tư xuống còn khoảng 30%. Việc này khiến tôi cảm thấy nhẹ nhõm hơn\", Wang - Giám đốc quỹ đầu tư tại Thượng Hải cho biết, đề cập đến đợt bán tháo mạnh của cổ phiếu Trung Quốc phiên 23/3.\r\n\r\nDù thị trường sau đó phục hồi phần nào, Wang vẫn chưa muốn mua vào, do biến động với các tài sản toàn cầu hiện rất lớn và khó đoán, từ cổ phiếu đến dầu, trái phiếu và vàng. \"Hôm nay bạn bắt đáy, nhưng hôm sau thị trường lại bán tháo. Khi có quá nhiều bất ổn, bạn phải giảm tỷ trọng để có thể ngủ yên mỗi đêm\", Wang nói.\r\n\r\nWang không phải trường hợp cá biệt. Từ Thượng Hải đến New York, các nhân viên giao dịch, nhà đầu tư, giám đốc quỹ... đều đang mất ngủ, làm việc cuối tuần, họp với khách hàng, liên tiếp xoay vòng danh mục và hồi hộp khi thực hiện giao dịch vào phút chót.\r\n\r\nBảng điện tử hiển thị chỉ số Kospi tại một phòng giao dịch ở Seoul (Hàn Quốc) ngày 4/3/2026. Ảnh: Reuters\r\n\r\nBảng điện tử hiển thị chỉ số Kospi tại một phòng giao dịch ở Seoul (Hàn Quốc) ngày 4/3/2026. Ảnh: Reuters\r\n\r\nXung đột tại Trung Đông đã kéo dài một tháng, lan rộng ra nhiều quốc gia trong khu vực. Việc Iran kiểm soát eo biển Hormuz và hạ tầng năng lượng tại Trung Đông bị tập kích khiến giá dầu thô toàn cầu tăng hơn 50%, làm dấy nỗi lo lạm phát và lãi suất toàn cầu bị đẩy lên cao.\r\n\r\nVàng - tài sản trú ẩn truyền thống - ghi nhận tháng giảm mạnh nhất kể từ năm 2008, với khoảng 16%. Lợi suất trái phiếu kho bạc Mỹ tăng 46 điểm cơ bản (0,46%) tháng này - mạnh nhất kể từ tháng 10/2024.\r\n\r\nMột số nhà đầu tư đang giao dịch dựa trên kinh nghiệm từ xung đột Nga - Ukraine năm 2022 hay đại dịch. Tuy nhiên, phần lớn cho rằng các bài học cũ không còn hiệu quả.\r\n\r\n\"Giờ gần như không còn tài sản trú ẩn nào. Trái phiếu kho bạc không hiệu quả, các đồng tiền an toàn như yen hay franc Thụy Sĩ cũng không. Vàng và bạc cũng vậy\", Rajeev De Mello - Giám đốc Đầu tư tại GAMA Asset Management cho biết. Ông gần đây phải làm việc xuyên cuối tuần và họp nhóm nhiều hơn.\r\n\r\nNguy cơ \"stagflation\" (lạm phát cao kèm tăng trưởng thấp) khiến nhà đầu tư bán tháo hầu hết tài sản, trừ đồng USD. \"Từ khi chiến sự nổ ra, chúng tôi giảm tỷ trọng cổ phiếu vì không còn nơi trú ẩn\", De Mello nói.\r\n\r\nThị trường chứng khoán châu Á chịu ảnh hưởng nặng nhất. Thị trường Hàn Quốc giảm khoảng 13% tháng này, trong khi chỉ số Nikkei của Nhật Bản sụt 9%. Các cổ phiếu Mỹ giảm nhẹ hơn, chỉ 6%.\r\n\r\nKenyon Tsev - Trưởng bộ phận giao dịch của Ngân hàng UBS tại Hong Kong, cho biết từ đầu tháng, mỗi ngày bộ phận của ông đều ghi nhận bán ròng với cổ phiếu TSMC - công ty lớn nhất châu Á về vốn hóa. Đây cũng là khoản đầu tư lớn của nhiều nhà đầu tư toàn cầu vào Đài Loan.\r\n\r\nMatthias Scheiber tại Allspring Global Investments cũng giảm tỷ trọng đầu tư tại thị trường mới nổi và tăng đầu tư vào Mỹ. Tuy nhiên, ông cảnh báo sức ép có thể tăng nếu các ngân hàng trung ương toàn cầu tăng lãi suất theo Australia.\r\n\r\nVới những người đi ngược xu hướng thị trường, áp lực đặc biệt lớn. Nhân viên giao dịch tại một công ty năng lượng cho biết chiến sự khiến họ mất ngủ, vì công ty nắm giữ các vị thế đặt cược giá dầu giảm.\r\n\r\n\"Tôi gần như không thể ngủ vào những ngày đầu chiến sự\", người này nói. Tuần sau đó với anh cũng rất căng thẳng do thị trường biến động mạnh và các cuộc họp nội bộ dày đặc.\r\n\r\nKenneth Goh - Giám đốc Quản lý tài sản cá nhân tại UOB Kay Hian (Singapore) cho biết ông mất ngủ không phải vì giao dịch thua lỗ, mà do phải quản lý danh mục khách hàng trong cú sốc chưa từng có. \"Công việc cứ biến đổi không ngừng. Nếu may mắn, tôi được ngủ lúc nửa đêm, còn không thì 3-4 giờ sáng\", ông nói.\r\n\r\nBất ổn tại Trung Đông cũng ảnh hưởng đến việc vay vốn của doanh nghiệp. Tại New York, các ngân hàng cam kết cấp khoản vay 18 tỷ USD cho thương vụ thâu tóm trị giá 55 tỷ USD của hãng sản xuất game Electronic Arts. Vì thế, họ phải theo dõi sát chiến sự để đánh giá khả năng lãi suất tăng tốc.\r\n\r\nSau khi Mỹ hôm 23/3 thông báo hoãn kế hoạch tấn công vào hạ tầng điện của Iran, các ngân hàng đã giảm lãi suất cho số trái phiếu trị giá khoảng 6,6 tỷ USD phát hành bằng nhiều đồng tiền. Ngày 27/3, Mỹ tiếp tục hoãn tấn công thêm 10 ngày.\r\n\r\nCác biến động liên tục khiến nhà đầu tư gần như không thể rời mắt khỏi màn hình. \"Bạn phải liên tục theo dõi, giám sát và tham gia thị trường. Điều này ảnh hưởng lớn đến tinh thần\", Mukesh Dave - Giám đốc Đầu tư tại Aravali Asset Management cho biết.\r\n\r\nDave từng trải qua cường độ tương tự vào năm 2008 và trong khủng hoảng tài chính châu Á cuối thập niên 1990. Dù vậy, ông chưa thể khẳng định tình hình hiện tại có nghiêm trọng như vậy hay không.\r\n\r\n\"Nếu tình trạng này kéo dài thêm một tuần nữa, chúng ta sẽ thấy rõ. Bạn không được phép mắc sai lầm, vì không có chỗ cho sai sót\", ông nói.\r\n\r\n', 'assets/uploads/thumb_69c958b2f01999.54024876_small.webp', 'published', 11, '2026-03-29 23:52:03', '2026-03-30 04:33:00', 5, 3),
(17, 'VinEnergo đầu tư 8 tỷ USD vào cụm nhà máy điện gió Gia Lai', 'Công ty Cổ phần Năng lượng VinEnergo ký hợp tác UBND tỉnh Gia Lai nhằm nghiên cứu, khảo sát tiềm năng, hướng đến đầu tư xây dựng cụm nhà máy điện gió 8 tỷ USD tại Gia Lai, ngày 28/3.\r\n\r\n', 'Theo thỏa thuận, dự án cụm nhà máy điện gió Gia Lai sẽ được triển khai theo hai giai đoạn, hướng tới quy mô hàng đầu khu vực. Trong đó, giai đoạn 1 dự kiến được triển khai với tổng công suất khoảng 2.000 MW, sau đó mở rộng quy mô lên khoảng 3.000 MW trong giai đoạn 2. Tổng vốn đầu tư dự kiến cho toàn bộ dự án là khoảng 210.000 tỷ đồng (gần 8 tỷ USD).\r\n\r\nKhi hoàn thành, dự án được kỳ vọng tạo ra quần thể năng lượng sạch khổng lồ, đảm bảo an ninh năng lượng quốc gia trong dài hạn, đồng thời tạo động lực phát triển kinh tế - xã hội cho tỉnh Gia Lai. Thỏa thuận đánh dấu bước tiến quan trọng trong chiến lược mở rộng đầu tư vào các dự án năng lượng tái tạo của VinEnergo, thể hiện cam kết của Tập đoàn Vingroup trong việc đồng hành cùng địa phương thúc đẩy chuyển đổi xanh, hướng tới mục tiêu phát triển bền vững.\r\n\r\nĐại diện tỉnh Gia Lai và lãnh đạo VinEnergo ký hợp tác xây dựng nhà máy điện gió Hòn Trâu (giai đoạn 1) và nhà máy điện gió Vĩnh Thuận. Ảnh: VinEnergo\r\nĐại diện tỉnh Gia Lai và lãnh đạo VinEnergo ký hợp tác xây dựng nhà máy điện gió Hòn Trâu (giai đoạn 1) và nhà máy điện gió Vĩnh Thuận. Ảnh: VinEnergo\r\n\r\nBà Nguyễn Hương Giang, Phó tổng giám đốc VinEnergo cho biết, thông qua việc phát triển nguồn năng lượng sạch, dự án sẽ góp phần đáng kể vào việc giảm thiểu ô nhiễm môi trường, ứng phó với biến đổi khí hậu toàn cầu.\r\n\r\n\"Chúng tôi cam kết đầu tư bài bản, lâu dài, tuân thủ quy định pháp luật nhằm bảo đảm hiệu quả kinh tế và hài hòa lợi ích giữa Nhà nước, địa phương, doanh nghiệp và người dân\", đại diện VinEnergo nhấn mạnh.\r\n\r\nÔng Nguyễn Hữu Quế, Phó Chủ tịch UBND tỉnh Gia Lai, cho biết địa phương đánh giá cao năng lực của doanh nghiệp trong lĩnh vực năng lượng tái tạo, đồng thời cam kết tạo điều kiện thuận lợi để nhà đầu tư sớm triển khai nghiên cứu và phát triển các dự án.\r\n\r\nHiện doanh nghiệp này đang đầu tư hàng loạt dự án năng lượng tái tạo quy mô lớn tại các địa phương như: Nhà máy Điện gió Kỳ Anh (Hà Tĩnh, công suất thiết kế 400 MW); Nhà máy Điện gió Eco Wind Kỳ Anh (Hà Tĩnh, công suất thiết kế 498 MW); Nhà máy điện mặt trời Điện Biên 1 (Điện Biên, công suất thiết kế 300 MW); Nhà máy điện mặt trời nổi Bản Chát 1 (Lai Châu, công suất thiết kế 250 MW); Nhà máy điện mặt trời nổi Bản Chát 2 (Lai Châu, công suất thiết kế 300 MW).\r\n\r\nVới định hướng mở rộng hoạt động ra toàn cầu, VinEnergo đã công bố mục tiêu phát triển 100 GW năng lượng tái tạo trong 3 năm tới tại các thị trường quốc tế cốt lõi như Bắc Mỹ, Bắc Âu, Địa Trung Hải, Đông Nam Á, đồng thời nghiên cứu các thị trường tiềm năng khác như Trung Á và châu Phi. Đơn vị hiện đã đạt thỏa thuận triển khai các danh mục dự án quốc tế đầu tiên tại Đan Mạch, Thụy Điển, Philippines với tổng công suất 10GW.\r\n\r\n', 'assets/uploads/thumb_69c958dd7dbc87.41757442_small.webp', 'published', 16, '2026-03-29 23:52:45', '2026-03-30 03:07:43', 6, 3),
(18, 'Viettel dự kiến tăng trưởng doanh thu tối thiểu 20% mỗi năm ở thị trường quốc tế', 'Tập đoàn Viettel đặt mục tiêu tiếp tục mở rộng kinh doanh ở nước ngoài, tăng trưởng doanh thu ít nhất 20% mỗi năm từ các thị trường này.\r\n\r\n', 'Mục tiêu này được Trung tướng Tào Đức Thắng, Chủ tịch, kiêm Tổng giám đốc Viettel chia sẻ tại lễ kỷ niệm 20 năm đầu tư ra nước ngoài của tập đoàn này hôm 28/3.\r\n\r\nKhởi đầu từ thị trường Campuchia vào năm 2006, đến nay, Viettel hiện diện tại 16 quốc gia (gồm các nước có hoạt động đầu tư, văn phòng đại diện). Đến nay, tỷ lệ hoàn vốn đầu tư nước ngoài của Viettel đã đạt 92%.\r\n\r\nHoạt động kinh doanh viễn thông tại 10 thị trường nước ngoài do Tổng Công ty Đầu tư Quốc tế Viettel (Viettel Global) phụ trách. Đây cũng là một trong 4 công ty họ Viettel niêm yết trên sàn chứng khoán, với vốn hóa khoảng 10 tỷ USD.\r\n\r\nÔng Tào Đức Thắng cho biết chương trình đầu tư ra nước ngoài của Viettel \"đã mang lại những kết quả rất thành công\". Thời gian tới, theo ông Thắng, doanh nghiệp này đặt mục tiêu tăng trưởng tối thiểu 20% mỗi năm ở quốc tế thông qua việc tiếp tục mở rộng thêm thị trường và sẵn sàng đương đầu với những thử thách mới.\r\n\r\nĐây là mức tăng trưởng cao, thách thức so với nhiều doanh nghiệp tại Việt Nam. Tuy nhiên, kế hoạch của Viettel cũng có cơ sở bởi năm ngoái, nguồn thu từ thị trường quốc tế của tập đoàn đạt khoảng 3,3 tỷ USD, tăng 24% so với 2024.\r\n\r\nViettel hiện giữ thị phần lớn nhất tại 7 trong số 10 thị trường đang kinh doanh nước ngoài (gồm 4 nước Đông Nam Á: Lào, Campuchia, Myanmar, Timor Leste; 4 nước châu Phi: Mozambique, Cameroon, Tanzania, Burundi; 2 nước châu Mỹ: Haiti, Peru).\r\n\r\nPhát biểu tại sự kiện, Bộ trưởng Quốc phòng Phan Văn Giang nói rằng công cuộc đầu tư ra nước ngoài của Viettel đã thể hiện năng lực làm chủ công nghiệp, cũng như chuyển từ doanh nghiệp nội địa thành tập đoàn công nghệ toàn cầu. Theo ông, việc này cũng đóng vai trò cầu nối thúc đẩy quan hệ hữu nghị, hợp tác giữa Việt Nam và các nước.\r\n\r\nBộ trưởng yêu cầu Viettel thời gian tới cần mở rộng không gian tăng trưởng, chuyển từ tham gia thị trường sang chủ động định hình thị trường và lựa chọn đối tác. Cùng với đó, Viettel cũng phải từng bước nâng cao vị trí, vai trò trong các lĩnh vực công nghệ chiến lược.\r\n\r\n', 'assets/uploads/thumb_69c95937182707.00156032_small.webp', 'published', 30, '2026-03-29 23:54:15', '2026-03-30 05:05:39', 3, 3),
(19, 'Nga sẽ cấm xuất khẩu xăng', 'Để đảm bảo nguồn cung trong nước, Nga có thể cấm xuất khẩu xăng từ ngày 1/4 đến hết tháng 7.\r\n\r\n', 'Ngày 27/3, Phó thủ tướng Nga Alexander Novak chỉ đạo Bộ Năng lượng soạn thảo nghị quyết cấm xuất khẩu xăng từ ngày 1/4. Quyết định này được đưa ra sau một cuộc họp về tình hình thị trường xăng dầu nước này. Trước đó, hãng thông tấn TASS cũng đưa tin lệnh cấm sẽ được duy trì đến ngày 31/7.\r\n\r\nÔng Novak cho biết diễn biến trên thị trường năng lượng toàn cầu do xung đột tại Trung Đông đang gây ra biến động giá lớn. Mục tiêu của quyết định trên là bình ổn giá và ưu tiên đảm bảo nguồn cung trong nước.\r\n\r\nMột tàu dầu thả neo tại thành phố cảng Nakhodka (Nga) tháng 12/2022. Ảnh: Reuters\r\nMột tàu dầu thả neo tại thành phố cảng Nakhodka (Nga) tháng 12/2022. Ảnh: Reuters\r\n\r\nChiến sự khiến dòng chảy năng lượng qua eo biển Hormuz gần như đình trệ gần một tháng qua. Đây là tuyến vận chuyển 20% dầu, khí LNG toàn cầu. Từ khi xung đột diễn ra, giá Brent đã tăng 53%, trong khi WTI tăng 45%.\r\n\r\nDiễn biến này khiến nhu cầu quốc tế với năng lượng của Nga tăng cao. Dầu thô Nga bị phương Tây áp trừng phạt từ sau chiến sự tại Ukraine năm 2022. Tuy nhiên, để hạ nhiệt giá dầu thế giới, Mỹ cho phép các nước mua dầu Nga đang vận chuyển trên biển đến ngày 11/4. Ấn Độ tháng này đã mua hơn 40 triệu thùng dầu Nga. Giới chức Thái Lan cũng đang tính đến phương án này.\r\n\r\nChính phủ Nga cho biết sản lượng chế biến dầu thô của Nga hiện vẫn tương đương năm ngoái, nhờ đó đảm bảo được nguồn cung các sản phẩm từ dầu. Năm ngoái, một số khu vực tại Nga ghi nhận thiếu xăng, do nhu cầu nhiên liệu tăng theo mùa và Ukraine tăng cường tấn công các cơ sở lọc dầu của Nga.\r\n\r\nVài năm qua, Nga nhiều lần áp lệnh hạn chế xuất khẩu xăng, dầu diesel để ghìm đà tăng của giá nhiên liệu và giải quyết thiếu hụt trong nước. Reuters trích các nguồn tin thân cận cho biết năm ngoái, nước này xuất khẩu gần 5 triệu tấn xăng, tương đương 117.000 thùng một ngày.\r\n\r\n', 'assets/uploads/thumb_69c9597eddbf76.52676181_small.webp', 'published', 47, '2025-03-29 23:55:27', '2026-03-30 04:04:20', 4, 3);

